mapper.insert:
		/*
             SQL ID : OnlnPltfrmStngDAO.onlnPltfrmStngRegist
             설  명 : 온라인플랫폼설정등록
         */
         INSERT INTO TB_LMS_ONLN_PLTFRM_STNG (
	     	  ONLN_PLTFRM_STNG_ID
			, PLTFRM_GBNCD
			, ORG_ID
			, PLTFRM_CNTN_ID
			, PLTFRM_CNTN_CLIENT_ID
			, PLTFRM_CNTN_CLIENT_PSWD
			, RGTR_ID
			, REG_DTTM
	     ) VALUES (
	     	  #{onlnPltfrmStngId}
			, #{pltfrmGbncd}
			, #{orgId}
			, #{pltfrmCntnId}
			, #{pltfrmCntnClientId}
			, #{pltfrmCntnClientPswd}
			, #{rgtrId}
			, FN_DTTM()
	     )

mapper.update:
		/*
             SQL ID : OnlnPltfrmStngDAO.onlnPltfrmStngModify
             설  명 : 온라인플랫폼설정수정
         */
        UPDATE TB_LMS_ONLN_PLTFRM_STGN SET
        	  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()
			, PLTFRM_CNTN_ID = #{pltfrmCntnId}
			, PLTFRM_CNTN_CLIENT_ID = #{pltfrmCntnClientId}
			, PLTFRM_CNTN_CLIENT_PSWD = #{pltfrmCntnClientPswd}
		 WHERE ONLN_PLTFRM_STNG_ID = #{onlnPltfrmStngId}
		   AND PLTFRM_GBNCD = #{pltfrmGbncd}
		   AND ORG_ID = #{orgId}

mapper.delete:
		/*
             SQL ID : OnlnPltfrmStngDAO.onlnPltfrmStngDelete
             설  명 : 온라인플랫폼설정삭제
         */
        DELETE FROM TB_LMS_ONLN_PLTFRM_STNG
         WHERE ONLN_PLTFRM_STNG_ID = #{onlnPltfrmStngId}
           AND PLTFRM_GBNCD = #{pltfrmGbncd}
           AND ORG_ID = #{orgId}

mapper.select:
		/*
             SQL ID : OnlnPltfrmStngDAO.onlnPltfrmStngSelect
             설  명 : 온라인플랫폼설정조회
         */
        SELECT
        	*
          FROM TB_LMS_ONLN_PLTFRM_STNG
         WHERE PLTFRM_GBNCD = #{pltfrmGbncd}
           AND ORG_ID = #{orgId}
